    ['name' => 'Steve Nelson', 'first_name' => 'Steve', 'last_name' => 'Nelson', 'aka' => 'Stjepan Mesaroš', 'gender' => 'Male', 'race' => 'White', 'state' => 'Pennsylvania', 'birthdate' => '1903-01-01', 'death_date' => '1993-12-11', 'description' => 'Croatian immigrant; Western PA CPUSA District Secretary; Spanish Civil War — Lincoln Battalion political commissar; XV International Brigade commissar. Two prosecutions: PA Sedition Act August 1950 (20 years + $10,000); federal Smith Act 1953 (5 years + $10,000). Pennsylvania v. Nelson, 350 U.S. 497 (1956) invalidated state sedition laws (federal preemption).', 'affiliation' => ['Communist Party USA (Western PA District Secretary)', 'Abraham Lincoln Brigade'], 'cases' => [['institution' => ['name' => 'Allegheny County / federal Pittsburgh courts — Smith Act + PA Sedition', 'city' => 'Pittsburgh', 'state' => 'Pennsylvania'], 'arrest_date' => '1950-08-15', 'sentenced_date' => '1953-08-01', 'release_date' => '1957-06-17', 'sentence' => '20 years PA state (vacated by Pennsylvania v. Nelson 1956); 5 years federal Smith Act (reversed by Yates 1957)', 'convicted' => 'Yes (both); both vacated', 'charges' => 'PA Sedition Act 1950 (vacated by federal preemption Pennsylvania v. Nelson, 350 U.S. 497 (1956)); Smith Act §2385 1953 (reversed Yates 1957).']]],
    ['name' => 'Junius Irving Scales', 'first_name' => 'Junius', 'middle_name' => 'Irving', 'last_name' => 'Scales', 'gender' => 'Male', 'race' => 'White', 'state' => 'North Carolina', 'birthdate' => '1920-03-26', 'death_date' => '2002-08-05', 'description' => 'Born in Greensboro, NC; great-uncle was NC Governor Alfred Moore Scales. Chair Carolinas District CPUSA; UNC Chapel Hill student/grad. US Army 4 years. Arrested 1954; convicted 1955 Greensboro federal court; reversed; retried & re-convicted 1958; Scales v. United States, 367 U.S. 203 (1961) — 5-4 affirmed (only conviction under Smith Act membership clause to stand). 6 years; entered USP Lewisburg October 1961. Sentence commuted by JFK Christmas Eve 1962 — last Smith Act prisoner released. Left CPUSA 1957 over Khrushchev Secret Speech.', 'affiliation' => ['Communist Party USA (Carolinas chair)'], 'cases' => [['institution' => ['name' => 'USP Lewisburg — Smith Act / Scales v. US', 'city' => 'Lewisburg', 'state' => 'Pennsylvania'], 'arrest_date' => '1954-11-18', 'sentenced_date' => '1958-12-15', 'release_date' => '1962-12-24', 'sentence' => '6 years federal prison; commuted by JFK Christmas Eve 1962', 'convicted' => 'Yes; affirmed Scales v. US 367 U.S. 203 (1961)', 'charges' => 'Smith Act 1940 § 2385 — membership clause (only conviction under that clause to stand). Scales v. United States, 367 U.S. 203 (1961). Last Smith Act prisoner.']]],

    // First Truman case
    ['name' => 'Carl Aldo Marzani', 'first_name' => 'Carl', 'middle_name' => 'Aldo', 'last_name' => 'Marzani', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1912-03-04', 'death_date' => '1994-12-11', 'description' => 'Italian immigrant 1924; OSS officer (WWII); briefly State Department; CPUSA NYC organizer; documentary filmmaker; Antonio Gramsci\'s first English translator/publisher. The first Truman-era political prosecution: indicted January 1947; convicted June 22, 1947 in DC federal court — 11 counts of fraud/false statements (concealing CP membership while on government payroll under EO 9835 Loyalty Order). 36 months; served 32 months. Wrote We Can Be Friends: Origins of the Cold War (1952) in prison.', 'affiliation' => ['OSS (former)', 'State Department (former)', 'Communist Party USA', 'Marzani & Munsell Press (publisher)'], 'cases' => [['institution' => ['name' => 'FCI Danbury — first Loyalty Order prosecution', 'city' => 'Danbury', 'state' => 'Connecticut'], 'arrest_date' => '1947-01-15', 'sentenced_date' => '1947-06-22', 'release_date' => '1950-08-15', 'sentence' => '36 months federal prison; served 32 months', 'convicted' => 'Yes', 'judge' => 'Hon. James M. Proctor (D.D.C.)', 'charges' => 'False statements to a federal agency (18 U.S.C. § 80, predecessor to § 1001), 11 counts — concealing CPUSA membership while on government payroll under President Truman\'s Loyalty Order EO 9835. First conviction under Truman Loyalty Program.']]],

