    // Rosenbergs / atomic spies
    ['name' => 'Julius Rosenberg', 'first_name' => 'Julius', 'last_name' => 'Rosenberg', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1918-05-12', 'death_date' => '1953-06-19', 'released' => false, 'description' => 'CCNY-trained electrical engineer who joined the Young Communist League at City College and recruited a wartime espionage network for Soviet intelligence while a civilian inspector at the Army Signal Corps lab at Fort Monmouth. Arrested July 17, 1950; tried jointly with Ethel and Morton Sobell; convicted March 29, 1951; sentenced to death April 5, 1951; executed at Sing Sing June 19, 1953 — the only American civilian executed for espionage during peacetime, alongside Ethel.', 'affiliation' => ['Communist Party USA', 'Young Communist League', 'U.S. Army Signal Corps (civilian engineer)'], 'cases' => [['institution' => ['name' => 'Sing Sing Prison — Rosenberg trial', 'city' => 'Ossining', 'state' => 'New York'], 'arrest_date' => '1950-07-17', 'sentenced_date' => '1951-04-05', 'death_in_custody_date' => '1953-06-19', 'sentence' => 'Death — executed June 19, 1953 at Sing Sing', 'convicted' => 'Yes', 'judge' => 'Hon. Irving R. Kaufman (S.D.N.Y.)', 'prosecutor' => 'Irving Saypol; Roy M. Cohn (asst.)', 'charges' => 'Conspiracy to commit espionage (50 U.S.C. § 32(a), Espionage Act of 1917).']]],
    ['name' => 'Ethel Greenglass Rosenberg', 'first_name' => 'Ethel', 'middle_name' => 'Greenglass', 'last_name' => 'Rosenberg', 'gender' => 'Female', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1915-09-28', 'death_date' => '1953-06-19', 'released' => false, 'description' => 'Grew up in a poor Jewish tenement family on Manhattan\'s Lower East Side; labor activist and aspiring singer. Married Julius Rosenberg 1939. Arrested August 11, 1950 — largely as leverage to compel Julius\'s confession. Convicted on the testimony of her brother David Greenglass and his wife Ruth that she typed espionage notes. Greenglass admitted in 2001 that he perjured himself about Ethel. Executed at Sing Sing June 19, 1953; case widely viewed as a grave miscarriage of justice.', 'affiliation' => ['Communist Party USA', 'Young Communist League'], 'cases' => [['institution' => ['name' => 'Sing Sing Prison — Rosenberg trial', 'city' => 'Ossining', 'state' => 'New York'], 'arrest_date' => '1950-08-11', 'sentenced_date' => '1951-04-05', 'death_in_custody_date' => '1953-06-19', 'sentence' => 'Death — executed June 19, 1953 at Sing Sing', 'convicted' => 'Yes', 'judge' => 'Hon. Irving R. Kaufman', 'prosecutor' => 'Irving Saypol; Roy M. Cohn (asst.)', 'charges' => 'Conspiracy to commit espionage (50 U.S.C. § 32(a)).']]],
    ['name' => 'Morton Sobell', 'first_name' => 'Morton', 'last_name' => 'Sobell', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1917-04-11', 'death_date' => '2018-12-26', 'description' => 'CCNY engineering classmate of Julius Rosenberg\'s who worked on military radar and ordnance contracts. Fled with his family to Mexico City June 22, 1950; on August 16 was abducted by armed men (likely Mexican secret police acting at FBI behest) and arrested at the Texas border. Convicted with the Rosenbergs March 1951; served 17 years 9 months at Alcatraz (1952-1958), Atlanta, and Lewisburg before parole January 14, 1969. In 2008 he admitted to the New York Times that he had passed military secrets to the Soviets during WWII.', 'affiliation' => ['Communist Party USA (alleged)', 'General Electric (former)', 'Reeves Electronics'], 'cases' => [['institution' => ['name' => 'Alcatraz / federal prisons — Rosenberg trial', 'city' => 'San Francisco', 'state' => 'California'], 'arrest_date' => '1950-08-18', 'sentenced_date' => '1951-04-05', 'release_date' => '1969-01-14', 'sentence' => '30 years; served 17 years 9 months', 'convicted' => 'Yes', 'judge' => 'Hon. Irving R. Kaufman', 'prosecutor' => 'Irving Saypol; Roy M. Cohn', 'charges' => 'Conspiracy to commit espionage (50 U.S.C. § 32(a)).']]],
    ['name' => 'David Greenglass', 'first_name' => 'David', 'last_name' => 'Greenglass', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1922-03-02', 'death_date' => '2014-07-01', 'description' => 'Ethel Rosenberg\'s younger brother; Army machinist at Los Alamos who passed plutonium-bomb sketches to Soviet courier Harry Gold in 1945. Arrested June 15, 1950; turned state\'s evidence — admitted in a 2001 interview with Sam Roberts that he perjured himself about Ethel typing notes to keep his wife Ruth out of prison. Sentenced to 15 years April 6, 1951; paroled after about 9.5 years; lived under an assumed name until his death.', 'affiliation' => ['U.S. Army (Manhattan Project machinist at Los Alamos)', 'Young Communist League (briefly)'], 'cases' => [['institution' => ['name' => 'USP Lewisburg — Rosenberg trial', 'city' => 'Lewisburg', 'state' => 'Pennsylvania'], 'arrest_date' => '1950-06-15', 'sentenced_date' => '1951-04-06', 'release_date' => '1960-11-15', 'sentence' => '15 years federal prison; served ~9.5 years', 'convicted' => 'Yes — guilty plea / cooperator', 'judge' => 'Hon. Irving R. Kaufman', 'prosecutor' => 'Irving Saypol', 'charges' => 'Conspiracy to commit espionage (50 U.S.C. § 32(a)).']]],
    ['name' => 'Harry Gold', 'first_name' => 'Harry', 'last_name' => 'Gold', 'aka' => 'Heinrich Golodnitsky', 'gender' => 'Male', 'race' => 'White', 'state' => 'Pennsylvania', 'birthdate' => '1910-12-11', 'death_date' => '1972-08-28', 'description' => 'Philadelphia industrial chemist who began passing Soviet intelligence economic and chemical secrets in 1934. As courier "Raymond" he received atomic-weapons data from Klaus Fuchs and David Greenglass during 1944-45. Arrested May 22, 1950 after Fuchs identified him from a photo; pled guilty. Sentenced to 30 years December 9, 1950 by Judge James P. McGranery. Served at USP Lewisburg; paroled May 18, 1966.', 'affiliation' => ['NKVD/Soviet intelligence (1934-1950)', 'Pennsylvania Sugar Co.'], 'cases' => [['institution' => ['name' => 'USP Lewisburg — atomic spy case', 'city' => 'Lewisburg', 'state' => 'Pennsylvania'], 'arrest_date' => '1950-05-22', 'sentenced_date' => '1950-12-09', 'release_date' => '1966-05-18', 'sentence' => '30 years federal prison', 'convicted' => 'Yes — guilty plea', 'judge' => 'Hon. James P. McGranery (E.D. Pa.)', 'prosecutor' => 'Gerald A. Gleeson', 'charges' => 'Conspiracy to commit espionage (50 U.S.C. § 32(a)).']]],

    // HUAC contempt
    ['name' => 'Dashiell Hammett', 'first_name' => 'Samuel', 'middle_name' => 'Dashiell', 'last_name' => 'Hammett', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1894-05-27', 'death_date' => '1961-01-10', 'description' => 'Inventor of hard-boiled detective fiction (The Maltese Falcon, The Thin Man); volunteered for the U.S. Army in both world wars; joined the CPUSA in the late 1930s. As a trustee of the Civil Rights Congress bail fund, refused on July 9, 1951 to identify the fund\'s contributors after four CRC defendants jumped bail. Judge Sylvester Ryan immediately convicted him of criminal contempt; six months at FCI Ashland, KY. The IRS then pursued him for back taxes; he died penniless of lung cancer.', 'affiliation' => ['Communist Party USA', 'Civil Rights Congress (bail-fund trustee)', 'U.S. Army (WWI and WWII)'], 'cases' => [['institution' => ['name' => 'FCI Ashland — Hammett HUAC/CRC contempt', 'city' => 'Ashland', 'state' => 'Kentucky'], 'arrest_date' => '1951-07-09', 'sentenced_date' => '1951-07-09', 'release_date' => '1951-12-09', 'sentence' => '6 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Sylvester J. Ryan (S.D.N.Y.)', 'charges' => 'Criminal contempt of court (18 U.S.C. § 401) for refusing to identify Civil Rights Congress bail-fund contributors.']]],
    ['name' => 'W. E. B. Du Bois', 'first_name' => 'William', 'middle_name' => 'Edward Burghardt', 'last_name' => 'Du Bois', 'gender' => 'Male', 'race' => 'Black', 'state' => 'Massachusetts', 'birthdate' => '1868-02-23', 'death_date' => '1963-08-27', 'description' => 'Harvard\'s first Black PhD; NAACP co-founder; sociologist; editor of The Crisis. Chaired the Peace Information Center, which circulated the Stockholm Peace Appeal calling for nuclear disarmament. The Justice Department indicted him February 9, 1951 for failing to register as a foreign agent under FARA. Tried November 1951 before Judge James M. McGuire; the case was dismissed for lack of evidence after defense attorney Vito Marcantonio moved for acquittal at the close of the prosecution\'s case (November 20, 1951). Passport revoked 1952-58. Died in Ghana 1963 at 95.', 'affiliation' => ['NAACP (co-founder)', 'Peace Information Center', 'Communist Party USA (joined 1961)'], 'cases' => [['institution' => ['name' => 'U.S. District Court, District of Columbia — U.S. v. Du Bois', 'city' => 'Washington', 'state' => 'District of Columbia'], 'arrest_date' => '1951-02-09', 'release_date' => '1951-11-20', 'sentence' => 'Acquitted; charges dismissed', 'convicted' => 'No — acquitted', 'judge' => 'Hon. James M. McGuire', 'charges' => 'Foreign Agents Registration Act (22 U.S.C. § 611 et seq.) — failure to register as agent of foreign principal (Stockholm Peace Appeal).']]],
    ['name' => 'Julius Emspak', 'first_name' => 'Julius', 'last_name' => 'Emspak', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1904-08-06', 'death_date' => '1962-04-26', 'description' => 'Founding General Secretary-Treasurer of the United Electrical, Radio and Machine Workers of America (UE) 1936-1962. Phi Beta Kappa Union College. Authored the UE\'s preamble; central to its policies of refusing Taft-Hartley affidavits and resisting Cold War anti-Communism. July 1950, HUAC cited him and five other UE leaders for contempt of Congress. Convicted; conviction reversed in Emspak v. United States, 349 U.S. 190 (1955), holding his Fifth Amendment invocation was sufficient.', 'affiliation' => ['United Electrical, Radio and Machine Workers of America (founding General Secretary-Treasurer)'], 'cases' => [['institution' => ['name' => 'U.S. District Court, D.C. — Emspak HUAC contempt', 'city' => 'Washington', 'state' => 'District of Columbia'], 'arrest_date' => '1950-07-15', 'sentenced_date' => '1952-06-15', 'release_date' => '1955-05-30', 'sentence' => 'Conviction reversed by SCOTUS Emspak v. US 349 U.S. 190 (1955)', 'convicted' => 'Yes; reversed', 'charges' => 'Contempt of Congress (2 U.S.C. § 192) for refusing to answer HUAC about UE membership.']]],

    // Trotskyist 1941 Minneapolis
    ['name' => 'James P. Cannon', 'first_name' => 'James', 'middle_name' => 'P.', 'last_name' => 'Cannon', 'aka' => 'James Patrick Cannon', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1890-02-11', 'death_date' => '1974-08-21', 'description' => 'National Secretary of the Socialist Workers Party (SWP); leading figure in American Trotskyism. Born in Rosedale, Kansas; founded CPUSA before being expelled in 1928 for supporting Trotsky. Co-founded the SWP in 1938. Convicted under the Smith Act in 1941 for opposing US entry into WWII; testimony published as the classic "Socialism on Trial" (1942). 16 months federal prison.', 'affiliation' => ['Socialist Workers Party (National Secretary)', 'Communist League of America', 'IWW (former)'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'prosecutor' => 'Victor E. Anderson', 'charges' => 'Conspiracy to advocate the overthrow of the U.S. government by force; advocating insubordination in the armed forces (Smith Act / Alien Registration Act of 1940, 18 U.S.C. § 2385). First Smith Act prosecution.']]],
    ['name' => 'Vincent Raymond Dunne', 'first_name' => 'Vincent', 'middle_name' => 'Raymond', 'last_name' => 'Dunne', 'aka' => 'V.R. Dunne; Ray Dunne', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1889-04-17', 'death_date' => '1970-02-17', 'description' => 'Central leader of the 1934 Minneapolis Teamsters strike; co-founder of American Trotskyism. Joined the IWW in Montana lumber camps before settling in Minneapolis. Expelled from the Communist Party in 1928 with Cannon for Trotskyism. Trotsky called him "the most effective labor leader in America." 16 months at FCI Sandstone. Remained an SWP leader until his death.', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544', 'IWW (former)'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'prosecutor' => 'Victor E. Anderson', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Farrell Dobbs', 'first_name' => 'Farrell', 'last_name' => 'Dobbs', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1907-07-25', 'death_date' => '1983-10-31', 'description' => 'Teamsters organizer who led the 1938-41 over-the-road truck driver organizing drives bringing a quarter-million Midwestern drivers into the union. Trotskyist under the Dunne brothers and Carl Skoglund. SWP National Secretary after Cannon; SWP presidential candidate in 1948, 1952, 1956, and 1960. 16 months at FCI Sandstone.', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'prosecutor' => 'Victor E. Anderson', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Albert Goldman', 'first_name' => 'Albert', 'last_name' => 'Goldman', 'aka' => 'Albert Verblen', 'gender' => 'Male', 'race' => 'White', 'state' => 'Illinois', 'birthdate' => '1897-01-01', 'death_date' => '1960-12-15', 'description' => 'Belarusian-Jewish-born Chicago lawyer who served as Leon Trotsky\'s American attorney and represented him at the 1937 Dewey Commission hearings in Mexico City. Originally a CP legal-defense attorney, expelled 1933 for Trotskyism. In the 1941 Minneapolis trial was both chief defense counsel and a defendant; made the closing argument for the SWP. Disbarred after his conviction. 16 months federal prison.', 'affiliation' => ['Socialist Workers Party', 'Workers Party (post-1946)', 'Illinois Bar (disbarred)'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'prosecutor' => 'Victor E. Anderson', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Felix Morrow', 'first_name' => 'Felix', 'last_name' => 'Morrow', 'aka' => 'Felix Mayrowitz', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1906-06-03', 'death_date' => '1988-05-28', 'description' => 'Trotskyist editor and theoretician. Edited the SWP\'s newspaper The Militant and its theoretical journal Fourth International from 1940. His book "Revolution and Counter-Revolution in Spain" (1938) is a classic Trotskyist analysis of the Spanish Civil War. After his Smith Act sentence, expelled from SWP 1946. Later became VP at Schocken Books.', 'affiliation' => ['Socialist Workers Party', 'Workers Party (post-1946)'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Carl Skoglund', 'first_name' => 'Carl', 'last_name' => 'Skoglund', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1884-04-10', 'death_date' => '1960-12-11', 'description' => 'Swedish-born Teamster organizer; co-founder of American Trotskyism. Emigrated 1911; joined the IWW; founding CPUSA. Expelled 1928 with Cannon for Trotskyism. President of Teamsters Local 544; central leader of 1934 Minneapolis truckers\' strike. After serving 16 months for Smith Act conviction, U.S. government tried to deport him for the rest of his life. Died in 1960 still under deportation order.', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544', 'IWW (former)', 'Communist Party USA (former)'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison; subjected to repeated deportation proceedings 1949-1960', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385); subsequent McCarran Act deportation proceedings.']]],
    ['name' => 'Harry DeBoer', 'first_name' => 'Harry', 'last_name' => 'DeBoer', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1903-01-01', 'death_date' => '1992-12-15', 'description' => 'Minneapolis coal-yard Teamster; leader of the 1934 Minneapolis Teamsters Strike, credited with developing the "cruising picket" tactic. Wounded by police gunfire on Bloody Friday during the 1934 strike. SWP labor activist for decades; authored the 1987 essay "How to Win Strikes: Lessons from the 1934 Minneapolis Truckers Strike."', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '12 months and a day', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Grace Holmes Carlson', 'first_name' => 'Grace', 'middle_name' => 'Holmes', 'last_name' => 'Carlson', 'gender' => 'Female', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1906-11-14', 'death_date' => '1992-07-07', 'description' => 'The only woman convicted in the 1941 Minneapolis Smith Act trial. PhD University of Minnesota 1933. Delegate to the SWP\'s founding 1938 convention; Minnesota state organizer; SWP\'s vice-presidential candidate 1948. Served 16 months alone at the federal women\'s prison at Alderson, WV. In 1952 abruptly left the SWP, returned to Catholicism, became a psychology professor advocating social justice as a "Catholic Marxist."', 'affiliation' => ['Socialist Workers Party (Minnesota state organizer)'], 'cases' => [['institution' => ['name' => 'Federal Prison Camp, Alderson — 1941 Minneapolis Smith Act', 'city' => 'Alderson', 'state' => 'West Virginia'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Jake Cooper', 'first_name' => 'Jake', 'last_name' => 'Cooper', 'aka' => 'Jacob Cooper', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1916-01-01', 'death_date' => '1990-12-15', 'description' => 'Minneapolis Teamster who served as one of Leon Trotsky\'s bodyguards at Coyoacán, Mexico for four months in 1940. Participant in 1934 Minneapolis Teamsters Strike. Following 16-month Smith Act sentence, lifelong Trotskyist; when Jack Barnes\'s SWP leadership abandoned Trotskyism in the 1980s, Cooper joined the expelled faction that formed Socialist Action.', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544', 'Socialist Action (later)'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Max Geldman', 'first_name' => 'Max', 'last_name' => 'Geldman', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'birthdate' => '1905-01-01', 'description' => 'Polish-Jewish-born Trotskyist organizer of WPA workers in Minneapolis. Born in Warsaw and brought to America as a child. Joined the Trotskyist movement in 1931. Led the July 1939 WPA workers\' strike. Notably, had previously been imprisoned at Sandstone for that 1939 strike — his second time there in 1944 was for the Smith Act. Remained in SWP for over 50 years.', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544 Federal Workers Section'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1945-01-15', 'sentence' => '12-16 months federal prison', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],
    ['name' => 'Carlos Hudson', 'first_name' => 'Carlos', 'last_name' => 'Hudson', 'gender' => 'Male', 'race' => 'White', 'state' => 'Minnesota', 'description' => 'Secretary of the Minneapolis branch of the Socialist Workers Party; editor of "544 Weekly," the newspaper of Teamsters Local 544.', 'affiliation' => ['Socialist Workers Party', 'Teamsters Local 544'], 'cases' => [['institution' => ['name' => 'FCI Sandstone — 1941 Minneapolis Smith Act', 'city' => 'Sandstone', 'state' => 'Minnesota'], 'arrest_date' => '1941-07-15', 'sentenced_date' => '1941-12-08', 'incarceration_date' => '1943-12-31', 'release_date' => '1944-12-15', 'sentence' => '12 months and a day', 'convicted' => 'Yes', 'judge' => 'Hon. Matthew M. Joyce', 'charges' => 'Smith Act conspiracy (18 U.S.C. § 2385).']]],

    // Taft-Hartley + Bridges
    ['name' => 'Ben Gold', 'first_name' => 'Ben', 'last_name' => 'Gold', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1898-01-01', 'death_date' => '1985-12-15', 'description' => 'Bessarabia-born; longtime Communist president of the International Fur and Leather Workers Union. Resigned publicly from CPUSA on August 24, 1950 to be able to sign the Taft-Hartley non-Communist affidavit. Indicted in August 1953, one day before the statute of limitations ran, charging the resignation was a sham. Convicted of perjury in 1954; sentenced 1-3 years; conviction reversed by SCOTUS 1957.', 'affiliation' => ['International Fur and Leather Workers Union (President)', 'Communist Party USA (until Aug 1950)'], 'cases' => [['institution' => ['name' => 'U.S. District Court, S.D.N.Y. — Taft-Hartley §9(h) prosecution', 'city' => 'New York', 'state' => 'New York'], 'arrest_date' => '1953-08-15', 'sentenced_date' => '1954-01-15', 'release_date' => '1957-06-15', 'sentence' => '1 to 3 years federal prison; reversed by SCOTUS 1957', 'convicted' => 'Yes; reversed', 'charges' => 'Perjury under 18 U.S.C. § 1621 in connection with non-Communist affidavit filed under §9(h), Taft-Hartley Act / LMRA 1947 (29 U.S.C. § 159(h)).']]],
    ['name' => 'Hugh Bryson', 'first_name' => 'Hugh', 'last_name' => 'Bryson', 'gender' => 'Male', 'race' => 'White', 'state' => 'California', 'description' => 'President of the National Union of Marine Cooks and Stewards, a left-led maritime union expelled from the CIO in 1950 for Communist domination. CPUSA member from at least 1937. Signed Taft-Hartley non-Communist affidavits in April 1951; tried and convicted 1955 under 18 U.S.C. § 1001 of falsely denying CPUSA affiliation. Conviction upheld at Bryson v. United States, 396 U.S. 64 (1969).', 'affiliation' => ['National Union of Marine Cooks and Stewards (President)', 'Communist Party USA'], 'cases' => [['institution' => ['name' => 'U.S. District Court, N.D. Cal. — Taft-Hartley §9(h)', 'city' => 'San Francisco', 'state' => 'California'], 'arrest_date' => '1954-06-15', 'sentenced_date' => '1955-06-15', 'release_date' => '1960-06-15', 'sentence' => '5 years federal prison + $10,000 fine', 'convicted' => 'Yes', 'charges' => 'False statement (18 U.S.C. § 1001) in non-Communist affidavit under Taft-Hartley §9(h). Affirmed Bryson v. United States, 396 U.S. 64 (1969).']]],
    ['name' => 'Maurice E. Travis', 'first_name' => 'Maurice', 'middle_name' => 'E.', 'last_name' => 'Travis', 'gender' => 'Male', 'race' => 'White', 'state' => 'Colorado', 'description' => 'CPUSA member who became secretary-treasurer and then president (1947) of the International Union of Mine, Mill and Smelter Workers (IUMMSW). Publicly renounced his CP membership to sign Taft-Hartley affidavits, then was indicted for perjury/false statement on the basis that the renunciation was fraudulent. Convicted in U.S. District Court for Colorado, but the Supreme Court reversed in Travis v. United States, 364 U.S. 631 (1961), holding that venue lay only in the District of Columbia where the affidavits were filed.', 'affiliation' => ['International Union of Mine, Mill and Smelter Workers (President)', 'Communist Party USA'], 'cases' => [['institution' => ['name' => 'U.S. District Court, District of Colorado — Taft-Hartley §9(h)', 'city' => 'Denver', 'state' => 'Colorado'], 'arrest_date' => '1956-06-15', 'sentenced_date' => '1959-06-15', 'release_date' => '1961-06-15', 'sentence' => 'Federal prison sentence; reversed on venue grounds by SCOTUS 1961', 'convicted' => 'Yes; reversed', 'charges' => 'False statement (18 U.S.C. § 1001) in Taft-Hartley §9(h) affidavit. Reversed Travis v. United States, 364 U.S. 631 (1961).']]],
    ['name' => 'Harry Bridges', 'first_name' => 'Harry', 'last_name' => 'Bridges', 'aka' => 'Alfred Renton Bridges', 'gender' => 'Male', 'race' => 'White', 'state' => 'California', 'birthdate' => '1901-07-28', 'death_date' => '1990-03-30', 'description' => 'Australian-born president of the International Longshore and Warehouse Union (ILWU) for 40 years. Led the 1934 West Coast Waterfront Strike; founded the ILWU in 1937. The U.S. government pursued him in four major proceedings (1939, 1941, 1948-55) attempting to deport him as a Communist. In 1949 indicted for perjury and conspiracy for denying CP membership in his 1945 naturalization. Convicted 1950, sentenced 5 years; jailed 3 weeks August 1950 before bail. Reversed by SCOTUS Bridges v. United States, 346 U.S. 209 (1953).', 'affiliation' => ['International Longshore and Warehouse Union (President)'], 'cases' => [['institution' => ['name' => 'U.S. District Court, N.D. Cal. — Bridges denaturalization/perjury', 'city' => 'San Francisco', 'state' => 'California'], 'arrest_date' => '1949-05-25', 'sentenced_date' => '1950-04-04', 'release_date' => '1953-06-15', 'sentence' => '5 years federal prison; conviction reversed by SCOTUS 1953; ~3 weeks served August 1950', 'convicted' => 'Yes; reversed', 'judge' => 'Hon. George B. Harris', 'prosecutor' => 'F. Joseph Donohue (DOJ Special Prosecutor)', 'charges' => 'Perjury (18 U.S.C. § 1621) and conspiracy to defraud the U.S. (18 U.S.C. § 371) in 1945 naturalization. Reversed Bridges v. United States, 346 U.S. 209 (1953).']]],

    // Espionage-perjury
    ['name' => 'Alger Hiss', 'first_name' => 'Alger', 'last_name' => 'Hiss', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1904-11-11', 'death_date' => '1996-11-15', 'description' => 'Harvard-trained State Department official who served as Secretary-General of the founding UN Conference at San Francisco in 1945; with FDR at Yalta. In 1948, Whittaker Chambers told HUAC that Hiss had been a secret CPUSA member who passed classified documents to the Soviets in the 1930s. The espionage statute of limitations had run; Hiss was indicted for perjury for denying Chambers\' allegations. After a hung jury in his first trial, convicted in January 1950; two concurrent 5-year terms. Maintained his innocence for 46 years until his death.', 'affiliation' => ['U.S. State Department (former)', 'Carnegie Endowment for International Peace (former)'], 'cases' => [['institution' => ['name' => 'USP Lewisburg — Hiss perjury trial', 'city' => 'Lewisburg', 'state' => 'Pennsylvania'], 'arrest_date' => '1948-12-15', 'sentenced_date' => '1950-01-25', 'incarceration_date' => '1951-03-22', 'release_date' => '1954-11-27', 'sentence' => 'Two concurrent 5-year federal sentences; served 44 months', 'convicted' => 'Yes', 'judge' => 'Hon. Henry W. Goddard (S.D.N.Y.)', 'prosecutor' => 'Thomas F. Murphy', 'charges' => 'Two counts of perjury, 18 U.S.C. § 1621 (denying passing documents to Chambers; denying seeing Chambers after Jan 1, 1937).']]],
    ['name' => 'William Walter Remington', 'first_name' => 'William', 'middle_name' => 'Walter', 'last_name' => 'Remington', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1917-10-25', 'death_date' => '1954-11-24', 'released' => false, 'description' => 'Phi Beta Kappa, magna cum laude Dartmouth economist (1939) who held senior posts at OPA, the War Production Board, and the Department of Commerce. In 1948 Elizabeth Bentley named him to HUAC as a Soviet source; in 1950 indicted for perjury for denying CPUSA membership. First conviction reversed; retried 1953 on two perjury counts; 3 years. Murdered in his cell at Lewisburg Federal Penitentiary in November 1954 by fellow inmates — frequently cited as one of the few homicides directly attributable to McCarthyism.', 'affiliation' => ['U.S. Department of Commerce (former)', 'OPA / War Production Board (former)'], 'cases' => [['institution' => ['name' => 'USP Lewisburg — Remington perjury trial', 'city' => 'Lewisburg', 'state' => 'Pennsylvania'], 'arrest_date' => '1950-06-08', 'sentenced_date' => '1953-03-15', 'incarceration_date' => '1953-04-15', 'death_in_custody_date' => '1954-11-24', 'sentence' => '3 years federal prison; murdered in custody Nov 24, 1954', 'convicted' => 'Yes', 'judge' => 'Hon. Vincent L. Leibell (S.D.N.Y., second trial)', 'prosecutor' => 'Thomas F. Murphy; later Roy Cohn', 'charges' => 'Perjury, 18 U.S.C. § 1621 (denying YCL membership at Dartmouth; denying providing information to Elizabeth Bentley).']]],

    // McCarran Act deportation
